class MimeTypeHelper { static String fromExtension(String ext) { switch (ext.toLowerCase().replaceAll('.', '')) { case 'pdf': return 'application/pdf'; case 'jpg': case 'jpeg': return 'image/jpeg'; case 'png': return 'image/png'; case 'mp4': return 'video/mp4'; case 'mp3': return 'audio/mpeg'; case 'txt': return 'text/plain'; case 'zip': return 'application/zip'; default: return 'application/octet-stream'; } } static bool isImage(String mime) => mime.startsWith('image/'); static bool isVideo(String mime) => mime.startsWith('video/'); static bool isAudio(String mime) => mime.startsWith('audio/'); }